#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define clear(x,y) memset(x,(y),sizeof(x));
#define INF (0x3f3f3f3f)
#define N 1005
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=(res<<1)+(res<<3)+(ch^48),ch=getchar();return res;
}
inline void write(int p){if(p>9)write(p/10);putchar('0'+p%10);}
namespace Solve
{
	int a[N],b[N],dp[N][256][16];
	inline int Cnt(int x,int y){return (!x||!y)?0:a[x]^a[y];}
	inline void main()
	{
		clear(a,0);clear(b,0);clear(dp,0x3f);dp[1][0][7]=0;
		int n=read();rep(1,n,i)a[i]=read(),b[i]=read();a[0]=b[0]=0;
		rep(1,n,i)rep(0,(1<<8)-1,j)rep(-8,7,k)if(dp[i][j][k+8]!=INF)
		{
			if(j&1){dp[i+1][j>>1][k+7]=min(dp[i+1][j>>1][k+7],dp[i][j][k+8]);continue;}
			int mxr=INF;rep(0,7,l)if(!(j&(1<<l)))
			{
				if(l+i>mxr)break; mxr=min(mxr,l+i+b[l+i]);
				dp[i][j^(1<<l)][l+8]=min(dp[i][j^(1<<l)][l+8],dp[i][j][k+8]+Cnt(i+l,i+k));
			}
		}
		int mi=INF;rep(0,8,i)mi=min(mi,dp[n][1][i]);write(mi);puts("");
	}
}
int main(){int T=read();while(T--)Solve::main();}
